import React from "react";
import { LinkContainer } from "react-router-bootstrap";
import { Table, Button, Row, Col } from "react-bootstrap";
import { FaTimes, FaEdit, FaTrash } from "react-icons/fa";
import Message from "../../component/message";
import Loader from "../../component/Loader";
import {
  useGetProductsQuery,
  useCreateProductMutation,
} from "../../slices/productApiSlice";
import { toast } from "react-toastify";

const ProductScreen = () => {
  const { data: products, isLoading, error } = useGetProductsQuery();
  const deleteHandler = (id) => {
    console.log(id);
  };

  const [
    createProduct,
    { isLoading: LoadingProduct, error: productError, refatch },
  ] = useCreateProductMutation();

  const creatingYourProduct = async () => {
    if (window.confirm("Are You Sure You Want To Create a New Product")) {
      try {
        await createProduct();
        refatch();
      } catch (err) {
        toast.error(err?.data?.message || err.error);
      }
    }
  };

  return (
    <>
      <Row className="align-items-center">
        <Col>
          <h2>Products</h2>
        </Col>
        <Col className="text-end">
          <Button className="btn-sm m-3" onClick={creatingYourProduct}>
            <FaEdit></FaEdit> CreateProduct
          </Button>
        </Col>
      </Row>
      {isLoading ? (
        <Loader></Loader>
      ) : error ? (
        <Message variant="danger">Error</Message>
      ) : (
        <>
          <Table striped hover responsive className="table-sm">
            <thead>
              <tr>
                <th>ID</th>
                <th>NAME</th>
                <th>PRICE</th>
                <th>CATEGORY</th>
                <th>BRAND</th>
                <th></th>
              </tr>
            </thead>
            <tbody>
              {products.map((product) => (
                <tr key={product._id}>
                  {/* Add a unique key for each item */}
                  <td>{product._id}</td>
                  <td>{product.name}</td>
                  <td>{product.price}</td>
                  <td>{product.category}</td>
                  <td>{product.brand}</td>
                  <td>
                    {/* Edit Button */}
                    <LinkContainer to={`/admin/product/${product._id}/edit`}>
                      <Button variant="light" className="btn-sm mx-2">
                        <FaEdit />
                      </Button>
                    </LinkContainer>

                    {/* Delete Button */}
                    <Button
                      variant="danger"
                      className="btn-sm"
                      onClick={() => deleteHandler(product._id)} // Pass the correct product ID
                    >
                      <FaTrash />
                    </Button>
                  </td>
                </tr>
              ))}
            </tbody>
          </Table>
        </>
      )}
    </>
  );
};

export default ProductScreen;
